styles.decidePy:
"""Momentum style — ride confirmed trends; sit out chop.

Uses snapshot coins.*.analysis (trend + multi-timeframe % changes).
No external LLM required.
"""
from __future__ import annotations
from typing import Any, Dict, List

from yetifi_arena import Decision, Snapshot

MAX_DECISIONS = 3
SIZE_PCT = 12.0
UP = {"UP", "STRONG_UP"}
DOWN = {"DOWN", "STRONG_DOWN"}


def _analysis(block: Dict[str, Any]) -> Dict[str, Any]:
    a = block.get("analysis")
    return a if isinstance(a, dict) else {}


def decide(snapshot: Snapshot) -> List[Decision]:
    coins = snapshot.get("coins") or {}
    if not isinstance(coins, dict):
        return []

    scored: List[tuple[float, str, str, float]] = []
    for symbol, block in coins.items():
        if not isinstance(block, dict):
            continue
        a = _analysis(block)
        trend = str(a.get("trend") or "NEUTRAL")
        ch15 = float(a.get("priceChange15m") or 0)
        ch1h = float(a.get("priceChange1h") or 0)
        vol = float(a.get("volatility") or 0)
        if vol > 5.0:
            continue
        if trend in UP and ch15 > 0.4:
            scored.append((ch15 + 0.25 * ch1h, symbol, "LONG", SIZE_PCT))
        elif trend in DOWN and ch15 < -0.4:
            scored.append((abs(ch15) + 0.25 * abs(ch1h), symbol, "SHORT", SIZE_PCT))

    scored.sort(key=lambda t: t[0], reverse=True)
    out: List[Decision] = []
    for _, symbol, action, size in scored[:MAX_DECISIONS]:
        out.append({
            "symbol": symbol,
            "action": action,  # type: ignore[typeddict-item]
            "positionSizePercent": size,
            "reason": f"momentum {action.lower()} on {symbol}",
        })
    return out

"""Conservative style — only strong multi-timeframe alignment; small size.

Uses snapshot coins.*.analysis. Prefers FLAT (empty list) when unsure.
No external LLM required.
"""
from __future__ import annotations
from typing import Any, Dict, List

from yetifi_arena import Decision, Snapshot

MAX_DECISIONS = 2
SIZE_PCT = 6.0


def _analysis(block: Dict[str, Any]) -> Dict[str, Any]:
    a = block.get("analysis")
    return a if isinstance(a, dict) else {}


def decide(snapshot: Snapshot) -> List[Decision]:
    coins = snapshot.get("coins") or {}
    if not isinstance(coins, dict):
        return []

    scored: List[tuple[float, str, str]] = []
    for symbol, block in coins.items():
        if not isinstance(block, dict):
            continue
        a = _analysis(block)
        trend = str(a.get("trend") or "NEUTRAL")
        ch15 = float(a.get("priceChange15m") or 0)
        ch30 = float(a.get("priceChange30m") or 0)
        ch1h = float(a.get("priceChange1h") or 0)
        vol = float(a.get("volatility") or 0)
        if vol > 3.5:
            continue
        if trend == "STRONG_UP" and ch15 > 0.8 and ch30 > 0.5 and ch1h > 0.3:
            scored.append((ch1h, symbol, "LONG"))
        elif trend == "STRONG_DOWN" and ch15 < -0.8 and ch30 < -0.5 and ch1h < -0.3:
            scored.append((abs(ch1h), symbol, "SHORT"))

    scored.sort(key=lambda t: t[0], reverse=True)
    out: List[Decision] = []
    for _, symbol, action in scored[:MAX_DECISIONS]:
        out.append({
            "symbol": symbol,
            "action": action,  # type: ignore[typeddict-item]
            "positionSizePercent": SIZE_PCT,
            "reason": f"conservative {action.lower()} — multi-TF align on {symbol}",
        })
    return out

"""Degen style — aggressive entries on short-horizon moves; larger size.

Uses snapshot coins.*.analysis. Cuts into volatility others avoid.
No external LLM required.
"""
from __future__ import annotations
from typing import Any, Dict, List

from yetifi_arena import Decision, Snapshot

MAX_DECISIONS = 3
SIZE_PCT = 22.0


def _analysis(block: Dict[str, Any]) -> Dict[str, Any]:
    a = block.get("analysis")
    return a if isinstance(a, dict) else {}


def decide(snapshot: Snapshot) -> List[Decision]:
    coins = snapshot.get("coins") or {}
    if not isinstance(coins, dict):
        return []

    scored: List[tuple[float, str, str]] = []
    for symbol, block in coins.items():
        if not isinstance(block, dict):
            continue
        a = _analysis(block)
        ch1 = float(a.get("priceChange1m") or 0)
        ch5 = float(a.get("priceChange5m") or 0)
        trend = str(a.get("trend") or "NEUTRAL")
        score = abs(ch5) * 2 + abs(ch1)
        if ch5 >= 0.35 or (trend in ("UP", "STRONG_UP") and ch1 > 0.15):
            scored.append((score, symbol, "LONG"))
        elif ch5 <= -0.35 or (trend in ("DOWN", "STRONG_DOWN") and ch1 < -0.15):
            scored.append((score, symbol, "SHORT"))

    scored.sort(key=lambda t: t[0], reverse=True)
    out: List[Decision] = []
    for _, symbol, action in scored[:MAX_DECISIONS]:
        out.append({
            "symbol": symbol,
            "action": action,  # type: ignore[typeddict-item]
            "positionSizePercent": SIZE_PCT,
            "reason": f"degen {action.lower()} chase on {symbol}",
        })
    return out
